/**
 * Unit tests for pre-compact-task-done-prompt hook.
 *
 * Heuristic fires when:
 *   - imminent zone reached (accumulator estimatedTokens ≥ 85% of window)
 *   - AND >= 2 of 3 signals match: gitQuiet, quiescent, breakpointKeywords
 *   - AND not opted out, AND outside 30-min cooldown
 *
 * Plus: ORK_NO_PRECOMPACT_PROMPT opt-out, telemetry to
 * .claude/telemetry/pre-compact-decisions.jsonl, nudge-outcome marker write
 * on fire (.claude/state/nudge-outcome-<sid>.json).
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
  readFileSync: vi.fn(() => ''),
  mkdirSync: vi.fn(),
  appendFileSync: vi.fn(),
  writeFileSync: vi.fn(),
}));

vi.mock('node:child_process', () => ({
  execFileSync: vi.fn(() => ''),
}));

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { preCompactTaskDonePrompt } from '../../lifecycle/pre-compact-task-done-prompt.js';
import { existsSync, readFileSync, appendFileSync, writeFileSync } from 'node:fs';
import { execFileSync } from 'node:child_process';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

function makeInput(): HookInput {
  return { tool_name: 'PreCompact', session_id: 'test', tool_input: {} };
}

const PROJECT_DIR = '/test/project';
const TEST_WINDOW = 200_000;
// Imminent zone at 85% of 200k = 170k. State puts us above that.
const ABOVE_IMMINENT = 175_000;

interface StubOpts {
  changedFiles?: number;
  spawnLogLines?: string[];
  commitSubject?: string;
  telemetryLines?: string[];
  /** When false, accumulator state is missing → imminent gate suppresses fire. */
  imminent?: boolean;
  /** Override accumulator state shape directly. */
  accumState?: Partial<{
    estimatedTokens: number;
    cacheReadTokens: number;
    cacheCreationTokens: number;
    crossings: Record<string, boolean>;
    firstSeenAt: string;
    updatedAt: string;
  }>;
}

function stubSignals(opts: StubOpts): void {
  vi.mocked(execFileSync).mockImplementation(((...args: unknown[]) => {
    const argv = args[1] as string[] | undefined;
    if (args[0] !== 'git' || !argv) return '';
    if (argv[0] === 'diff') {
      const n = opts.changedFiles ?? 0;
      return Array.from({ length: n }, (_, i) => `file-${i}.txt`).join('\n');
    }
    if (argv[0] === 'log' && argv.includes('--format=%s')) {
      return opts.commitSubject ?? '';
    }
    return '';
  }) as unknown as typeof execFileSync);

  const inImminent = opts.imminent ?? true;
  const accumState = inImminent
    ? {
        estimatedTokens: ABOVE_IMMINENT,
        cacheReadTokens: 0,
        cacheCreationTokens: 0,
        crossings: { 'imminent:170000': true },
        firstSeenAt: new Date(Date.now() - 60 * 60 * 1000).toISOString(),
        updatedAt: new Date(Date.now() - 60_000).toISOString(),
        ...opts.accumState,
      }
    : null;

  vi.mocked(existsSync).mockImplementation(((path: unknown) => {
    const p = String(path);
    if (p.includes('token-accum.json')) return accumState !== null;
    if (p.endsWith('subagent-spawns.jsonl')) return !!opts.spawnLogLines?.length;
    if (p.endsWith('pre-compact-decisions.jsonl')) return !!opts.telemetryLines?.length;
    return false;
  }) as unknown as typeof existsSync);

  vi.mocked(readFileSync).mockImplementation(((path: unknown) => {
    const p = String(path);
    if (p.includes('token-accum.json') && accumState) return JSON.stringify(accumState);
    if (p.endsWith('subagent-spawns.jsonl')) return (opts.spawnLogLines ?? []).join('\n');
    if (p.endsWith('pre-compact-decisions.jsonl')) return (opts.telemetryLines ?? []).join('\n');
    return '';
  }) as unknown as typeof readFileSync);
}

const ENV_KEYS = ['ORK_NO_PRECOMPACT_PROMPT', 'CLAUDE_MAX_CONTEXT', 'ORK_CTX_IMMINENT_PCT', 'ORK_NO_CACHE_AWARENESS'];
function clearEnv() {
  for (const k of ENV_KEYS) delete process.env[k];
}

describe('preCompactTaskDonePrompt', () => {
  let ctx: ReturnType<typeof createTestContext>;

  beforeEach(() => {
    vi.clearAllMocks();
    ctx = createTestContext({ projectDir: PROJECT_DIR });
    clearEnv();
    process.env.CLAUDE_MAX_CONTEXT = String(TEST_WINDOW);
  });

  afterEach(() => clearEnv());

  describe('fire path (imminent + heuristic matches)', () => {
    it('blocks compact when gitQuiet + breakpointKeywords fire (#1477 git log subject)', () => {
      stubSignals({
        changedFiles: 0,
        commitSubject: 'feat(M118): merged PR #1463 to main',
        spawnLogLines: [],
      });
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(false);
      expect(result.decision).toBe('block');
      expect(result.stopReason).toContain('/clear');
      expect(result.stopReason).toContain('/compact');
    });

    it('blocks when all three signals match', () => {
      stubSignals({
        changedFiles: 1,
        commitSubject: 'chore(main): release 7.65.0',
        spawnLogLines: [
          JSON.stringify({
            timestamp: new Date(Date.now() - 30 * 60 * 1000).toISOString(),
            subagent_type: 'old',
          }),
        ],
      });
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(false);
      expect(result.decision).toBe('block');
    });

    it('writes a fired=true telemetry entry on fire', () => {
      stubSignals({
        changedFiles: 0,
        commitSubject: 'Merge pull request #999 from main',
        spawnLogLines: [
          JSON.stringify({
            timestamp: new Date(Date.now() - 30 * 60 * 1000).toISOString(),
            subagent_type: 'Explore',
          }),
        ],
      });
      preCompactTaskDonePrompt(makeInput(), ctx);
      expect(appendFileSync).toHaveBeenCalledTimes(1);
      const [telemetryPath, body] = vi.mocked(appendFileSync).mock.calls[0];
      expect(String(telemetryPath)).toContain('pre-compact-decisions.jsonl');
      const entry = JSON.parse(String(body).trim());
      expect(entry.fired).toBe(true);
      expect(entry.signals).toEqual({
        gitQuiet: true,
        quiescent: true,
        breakpointKeywords: true,
      });
      expect(entry.cacheHeat).toBeDefined();
    });

    it('writes a nudge-outcome marker on fire (#1476)', () => {
      stubSignals({
        changedFiles: 0,
        commitSubject: 'merged main',
      });
      preCompactTaskDonePrompt(makeInput(), ctx);
      expect(writeFileSync).toHaveBeenCalled();
      const calls = vi.mocked(writeFileSync).mock.calls;
      const markerCall = calls.find(c => String(c[0]).includes('nudge-outcome-'));
      expect(markerCall).toBeDefined();
      const marker = JSON.parse(String(markerCall![1]));
      expect(marker.sessionId).toBeDefined();
      expect(marker.firedAt).toBeDefined();
      expect(marker.resolved).toBe(false);
    });

    it('uses cache-warm phrasing in stopReason when cache hot (#1479)', () => {
      stubSignals({
        changedFiles: 0,
        commitSubject: 'merged main',
        accumState: {
          cacheReadTokens: 150_000, // > default 50k threshold
        },
      });
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.stopReason).toContain('warm');
      expect(result.stopReason).toContain('cache');
      expect(result.stopReason).toContain('150,000');
    });
  });

  describe('imminent-zone gate (#1480)', () => {
    it('stays silent when accumulator state is missing', () => {
      stubSignals({
        changedFiles: 0,
        commitSubject: 'merged main',
        spawnLogLines: [],
        imminent: false,
      });
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      const body = JSON.parse(String(vi.mocked(appendFileSync).mock.calls[0][1]).trim());
      expect(body.belowImminentZone).toBe(true);
      expect(body.fired).toBe(false);
    });

    it('stays silent when below imminent threshold', () => {
      stubSignals({
        changedFiles: 0,
        commitSubject: 'merged main',
        accumState: {
          estimatedTokens: 80_000, // 40% of 200k window — below imminent
        },
      });
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      const body = JSON.parse(String(vi.mocked(appendFileSync).mock.calls[0][1]).trim());
      expect(body.belowImminentZone).toBe(true);
    });
  });

  describe('silent path (heuristic misses)', () => {
    it('does not fire when only one signal matches', () => {
      stubSignals({ changedFiles: 1 }); // gitQuiet only
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    it('counts a noisy tree (>2 files) against gitQuiet', () => {
      stubSignals({
        changedFiles: 10,
        commitSubject: 'merged PR',
        spawnLogLines: [
          JSON.stringify({
            timestamp: new Date(Date.now() - 30 * 60 * 1000).toISOString(),
            subagent_type: 'Explore',
          }),
        ],
      });
      // gitQuiet=false, quiescent=true, kws=true → 2/3 → still fires
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(false);
      expect(result.decision).toBe('block');
    });

    it('counts recent subagent spawns against quiescent', () => {
      stubSignals({
        changedFiles: 10,
        spawnLogLines: [
          JSON.stringify({
            timestamp: new Date(Date.now() - 60 * 1000).toISOString(),
            subagent_type: 'Explore',
          }),
        ],
        commitSubject: 'merged PR',
      });
      // Only kws fires → silent (1/3)
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    it('writes a fired=false telemetry entry when silent', () => {
      stubSignals({ changedFiles: 10 });
      preCompactTaskDonePrompt(makeInput(), ctx);
      const body = JSON.parse(String(vi.mocked(appendFileSync).mock.calls[0][1]).trim());
      expect(body.fired).toBe(false);
    });
  });

  describe('breakpoint keyword matching (#1477)', () => {
    it('matches uppercase commit subject', () => {
      stubSignals({
        changedFiles: 0,
        commitSubject: 'MERGED PR #42 TO MAIN',
        spawnLogLines: [
          JSON.stringify({
            timestamp: new Date(Date.now() - 30 * 60 * 1000).toISOString(),
            subagent_type: 'Explore',
          }),
        ],
      });
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(false);
    });

    it('matches "Merge pull request" GitHub default subject', () => {
      stubSignals({
        changedFiles: 1,
        commitSubject: 'Merge pull request #203 from yonatangross/feature-x',
        spawnLogLines: [
          JSON.stringify({
            timestamp: new Date(Date.now() - 30 * 60 * 1000).toISOString(),
            subagent_type: 'workflow-architect',
          }),
        ],
      });
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(false);
    });

    it('does NOT match generic feat: prefix (avoids over-firing on mid-task commits)', () => {
      stubSignals({
        changedFiles: 0,
        commitSubject: 'feat(thing): add new helper',
        spawnLogLines: [
          JSON.stringify({
            timestamp: new Date(Date.now() - 30 * 60 * 1000).toISOString(),
            subagent_type: 'Explore',
          }),
        ],
      });
      // gitQuiet + quiescent only (kws=false) → 2/3 → still fires
      // Just asserting the keyword check itself is false
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      const body = JSON.parse(String(vi.mocked(appendFileSync).mock.calls[0][1]).trim());
      expect(body.signals.breakpointKeywords).toBe(false);
      // 2/3 signals fire so result is still block
      expect(result.continue).toBe(false);
    });

    it('returns false when git log fails (non-repo)', () => {
      vi.mocked(execFileSync).mockImplementation(((...args: unknown[]) => {
        const argv = args[1] as string[];
        if (argv?.[0] === 'log') throw new Error('not a git repo');
        return '';
      }) as unknown as typeof execFileSync);
      stubSignals({ changedFiles: 0 });
      // git diff returns 0 so gitQuiet=true, but kws fails → only 1 signal
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(true);
    });
  });

  describe('cooldown suppression', () => {
    it('skips firing when last fire was < 30 min ago', () => {
      const tenMinAgo = new Date(Date.now() - 10 * 60 * 1000).toISOString();
      stubSignals({
        changedFiles: 0,
        commitSubject: 'merged PR',
        telemetryLines: [JSON.stringify({ timestamp: tenMinAgo, fired: true, signals: {} })],
      });
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      const body = JSON.parse(String(vi.mocked(appendFileSync).mock.calls[0][1]).trim());
      expect(body.cooldown).toBe(true);
    });

    it('re-fires after cooldown expires', () => {
      const fortyMinAgo = new Date(Date.now() - 40 * 60 * 1000).toISOString();
      stubSignals({
        changedFiles: 0,
        commitSubject: 'merged PR',
        telemetryLines: [JSON.stringify({ timestamp: fortyMinAgo, fired: true, signals: {} })],
      });
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(false);
      expect(result.decision).toBe('block');
    });
  });

  describe('opt-out', () => {
    it('returns silent when ORK_NO_PRECOMPACT_PROMPT=1 even with fire signals', () => {
      stubSignals({
        changedFiles: 0,
        commitSubject: 'merged PR',
      });
      process.env.ORK_NO_PRECOMPACT_PROMPT = '1';
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(true);
      const body = JSON.parse(String(vi.mocked(appendFileSync).mock.calls[0][1]).trim());
      expect(body.optOut).toBe(true);
      expect(body.fired).toBe(false);
    });
  });

  describe('graceful degradation', () => {
    it('handles git failure without throwing', () => {
      vi.mocked(execFileSync).mockImplementation((() => {
        throw new Error('not a git repo');
      }) as unknown as typeof execFileSync);
      vi.mocked(existsSync).mockReturnValue(false);
      const result = preCompactTaskDonePrompt(makeInput(), ctx);
      expect(result.continue).toBe(true);
    });
  });
});
